export function getCalculatedInstallments(planDuration, totalAmount) {
    const startDate = new Date()
    const calculatedInstallment = Number(totalAmount) / Number(planDuration)
    return Array.from({ length: planDuration }, (_, i) => {
        const date = new Date(startDate)
        date.setMonth(date.getMonth() + i)
        return { dueDate: date.toISOString().slice(0, 10), dueDateLabel: date.toLocaleDateString(), dueAmt: calculatedInstallment }
    })
}
